-- CDS annotation for Fiori tile columns:
@UI.headerInfo: {
  typeName: 'Purchase Order',
  typeNamePlural: 'Purchase Orders',
  title: { value: 'PO_Number' }
}
define view ZC_PO_FIORI_LIST
  as select from ZI_PURCHASE_ORDER
{
  @UI.lineItem: [{ position: 10, label: 'PO Number' }]
  @UI.selectionField: [{ position: 10 }]
  key PO_Number,

  @UI.lineItem: [{ position: 20, label: 'Vendor' }]
  vendor_name,

  @UI.lineItem: [{ position: 30, label: 'Amount' }]
  @Semantics.amount.currencyCode: 'Currency'
  net_value
  -- Functional adds new field request:
  -- Technical adds here with @UI.lineItem
  -- Fiori tile automatically shows new column
}

-- DCL connecting to PFCG authorization object:
-- Functional maintains PFCG role with:
-- Authorization Object: V_VBAK_VKO
-- Field VKORG: 1000, 2000 (user's allowed sales orgs)

@AccessControl.authorizationCheck: #CHECK
define view ZI_SALES_ORDER
  as select from vbak
{ key vbak.vbeln, vbak.vkorg, vbak.kunnr }

-- DCL Source (technical team creates once):
@MappingRole: true
define role ZI_SALES_ORDER {
  grant select on ZI_SALES_ORDER
  where (vkorg) = aspect pfcg_auth(V_VBAK_VKO,
                                   VKORG, ACTVT = '03');
}
-- Result for functional:
-- User with PFCG role VKORG=1000 -> sees only 1000 orders
-- User with PFCG role VKORG=1000,2000 -> sees both
-- No additional configuration needed per Fiori app
